import React, { createContext, useState, useContext, useEffect } from 'react';
import axios from 'axios';

const CartContext = createContext();

export const CartProvider = ({ children }) => {
  const [cartItems, setCartItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Optionally load initial cart items from the database
  useEffect(() => {
    const fetchCart = async () => {
      try {
        setLoading(true);
        const response = await axios.get("http://localhost:3000/api/v1/cart");
        setCartItems(response.data);
      } catch (err) {
        console.error("Error fetching cart:", err);
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };
    fetchCart();
  }, []);

  const addToCart = async (product) => {
    // Check if the product is already in the cart
    const existing = cartItems.find(item => item.product._id === product._id);
    if (existing) {
      updateQuantity(product._id, existing.quantity + 1);
    } else {
      const newItem = { product, quantity: 1 };
      try {
        // Call your backend API to add/update the cart
        await axios.post("http://localhost:3000/api/v1/cart", {
          productId: product._id,
          quantity: 1
        });
        setCartItems([...cartItems, newItem]);
      } catch (err) {
        console.error("Error adding product to cart:", err);
      }
    }
  };

  const removeFromCart = async (productId) => {
    try {
      await axios.delete(`http://localhost:3000/api/v1/cart/${productId}`);
      setCartItems(cartItems.filter(item => item.product._id !== productId));
    } catch (err) {
      console.error("Error removing product from cart:", err);
    }
  };

  const updateQuantity = async (productId, quantity) => {
    try {
      await axios.put(`http://localhost:3000/api/v1/cart/${productId}`, { quantity });
      setCartItems(cartItems.map(item => {
        if (item.product._id === productId) {
          return { ...item, quantity };
        }
        return item;
      }));
    } catch (err) {
      console.error("Error updating quantity:", err);
    }
  };

  const clearCart = async () => {
    try {
      await axios.delete("http://localhost:3000/api/v1/cart");
      setCartItems([]);
    } catch (err) {
      console.error("Error clearing cart", err);
    }
  };

  const value = { cartItems, loading, error, addToCart, removeFromCart, updateQuantity, clearCart };

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
};

export const useCart = () => useContext(CartContext);
